// Servicio para el catálogo de inspecciones
const API_BASE_URL = 'http://localhost:3001/api';

const inspectionCatalogService = {
  // Obtener todas las inspecciones del catálogo
  getAllInspections: async () => {
    try {
      const response = await fetch(`${API_BASE_URL}/inspection-catalog`);
      if (!response.ok) throw new Error('Error fetching inspections');
      return await response.json();
    } catch (error) {
      console.error('Error fetching inspections:', error);
      // Retornar datos mock para desarrollo
      return [
        {
          id: 1,
          name: 'Espesor de Recubrimiento',
          type: 'medicion',
          description: 'Medición del espesor del recubrimiento de zinc en piezas metálicas',
          acceptance_criteria: 'Espesor mínimo según especificación de cliente',
          tolerance_min: 25,
          tolerance_max: 35,
          unit: 'μm',
          observations: 'Realizar en 3 puntos diferentes y promediar',
          is_active: true,
          created_at: '2024-01-15T10:00:00Z',
          updated_at: '2024-01-15T10:00:00Z'
        },
        {
          id: 2,
          name: 'Prueba de Adhesión',
          type: 'laboratorio',
          description: 'Verificación de la adhesión del recubrimiento mediante prueba de cinta',
          acceptance_criteria: 'Sin desprendimiento del recubrimiento',
          tolerance_min: null,
          tolerance_max: null,
          unit: null,
          observations: 'Según ASTM D3359',
          is_active: true,
          created_at: '2024-01-15T10:00:00Z',
          updated_at: '2024-01-15T10:00:00Z'
        },
        {
          id: 3,
          name: 'Inspección Visual de Superficie',
          type: 'visual',
          description: 'Revisión visual de defectos superficiales',
          acceptance_criteria: 'Sin grietas, porosidades o defectos visibles',
          tolerance_min: null,
          tolerance_max: null,
          unit: null,
          observations: 'Iluminación mínima de 500 lux',
          is_active: true,
          created_at: '2024-01-15T10:00:00Z',
          updated_at: '2024-01-15T10:00:00Z'
        }
      ];
    }
  },

  // Crear nueva inspección
  createInspection: async (inspectionData) => {
    try {
      const response = await fetch(`${API_BASE_URL}/inspection-catalog`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(inspectionData),
      });
      if (!response.ok) throw new Error('Error creating inspection');
      return await response.json();
    } catch (error) {
      console.error('Error creating inspection:', error);
      throw error;
    }
  },

  // Actualizar inspección existente
  updateInspection: async (id, inspectionData) => {
    try {
      const response = await fetch(`${API_BASE_URL}/inspection-catalog/${id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(inspectionData),
      });
      if (!response.ok) throw new Error('Error updating inspection');
      return await response.json();
    } catch (error) {
      console.error('Error updating inspection:', error);
      throw error;
    }
  },

  // Eliminar inspección
  deleteInspection: async (id) => {
    try {
      const response = await fetch(`${API_BASE_URL}/inspection-catalog/${id}`, {
        method: 'DELETE',
      });
      if (!response.ok) throw new Error('Error deleting inspection');
      return true;
    } catch (error) {
      console.error('Error deleting inspection:', error);
      throw error;
    }
  },

  // Obtener inspección por ID
  getInspectionById: async (id) => {
    try {
      const response = await fetch(`${API_BASE_URL}/inspection-catalog/${id}`);
      if (!response.ok) throw new Error('Error fetching inspection');
      return await response.json();
    } catch (error) {
      console.error('Error fetching inspection:', error);
      throw error;
    }
  },

  // Obtener inspecciones por tipo
  getInspectionsByType: async (type) => {
    try {
      const response = await fetch(`${API_BASE_URL}/inspection-catalog?type=${type}`);
      if (!response.ok) throw new Error('Error fetching inspections by type');
      return await response.json();
    } catch (error) {
      console.error('Error fetching inspections by type:', error);
      throw error;
    }
  },

  // Obtener inspecciones activas
  getActiveInspections: async () => {
    try {
      const response = await fetch(`${API_BASE_URL}/inspection-catalog?active=true`);
      if (!response.ok) throw new Error('Error fetching active inspections');
      return await response.json();
    } catch (error) {
      console.error('Error fetching active inspections:', error);
      throw error;
    }
  }
};

export default inspectionCatalogService;
